UPDATE BOARD_COMMENT
SET CONTENT = #{content}, UPDATED_AT = SYSTIMESTAMP
WHERE COMMENT_ID = #{commentId}

UPDATE BOARD
SET TITLE = #{title}, CONTENT = #{content, jdbcType=CLOB}, ANIMAL_ID = #{animalId, jdbcType=NUMERIC}, UPDATED_AT = SYSTIMESTAMP
WHERE BOARD_ID = #{boardId}

UPDATE BOARD_IMAGE

SET LINK_URL = #{linkUrl, jdbcType=VARCHAR}

WHERE BOARD_ID = #{boardId}

