    WHERE PARENT_ID = #{parentAnimalId}
    )
    )









            AND UPPER(B.TITLE)
            LIKE '%' || UPPER(#{keyword}) || '%'





            AND DBMS_LOB.INSTR(
            B.CONTENT,
            #{keyword}
            ) > 0





            AND UPPER(
            NVL(M.NICKNAME, '')
            ) LIKE '%' || UPPER(#{keyword}) || '%'





            AND (
            UPPER(B.TITLE)
